const users2 = $('Fetch 2 Days Remaining').first().json;
const users1 = $('Fetch 1 Day Remaining').first().json;
const users0 = $('Fetch 0 Days Remaining').first().json;
const accuracy = $('Fetch 7-Day Accuracy').first().json;

const allUsers = [];

const addUsers = (data, tier) => {
  const list = Array.isArray(data) ? data : (data.users || []);
  list.forEach(u => allUsers.push({ ...u, tier, daysRemaining: tier === 'gentle' ? 2 : tier === 'urgent' ? 1 : 0 }));
};

addUsers(users2, 'gentle');
addUsers(users1, 'urgent');
addUsers(users0, 'final');

if (allUsers.length === 0) {
  return [{ json: { skip: true, message: 'No trial-expiring users found' } }];
}

return allUsers.map(user => ({
  json: {
    skip: false,
    userId: user.telegram_id || user.chat_id || user.id,
    username: user.username || user.first_name || 'there',
    tier: user.tier,
    daysRemaining: user.daysRemaining,
    accuracy: JSON.stringify(accuracy)
  }
}));

const { tier, username, daysRemaining, accuracy } = $json;

let tierInstructions = '';
if (tier === 'gentle') {
  tierInstructions = `This is a GENTLE reminder (2 days left). Tone: friendly, informative. Mention the accuracy stats to show value. Suggest they explore features they might have missed. Do NOT be pushy.`;
} else if (tier === 'urgent') {
  tierInstructions = `This is an URGENT reminder (last full day). Tone: warm but with clear urgency. Emphasize what they'll lose access to tomorrow. Highlight the best recent prediction wins.`;
} else {
  tierInstructions = `This is the FINAL notice (trial ends tonight). Tone: direct, honest, respectful. Tell them exactly what happens when the trial ends. Make the upgrade path crystal clear. One strong CTA.`;
}

const prompt = `Write a personalized Telegram DM for a trial user named "${username}" whose Premium trial has ${daysRemaining} day(s) remaining.

${tierInstructions}

7-Day Performance Data: ${accuracy}

Rules:
- Use HTML formatting (<b>, <i>, <code>) — NOT Markdown
- Keep it under 800 characters
- Include the user's name naturally
- Reference specific accuracy numbers from the data
- End with a clear call-to-action
- Never give financial advice
- Make it feel personal, not templated
- Vary your opening line — do NOT start with "Hey" every time`;

return [{ json: { prompt, userId: $json.userId } }];

const response = $input.first().json;
let text = '';

if (response.content && response.content.length > 0) {
  text = response.content[0].text;
} else {
  text = '<b>Your BTC Seer Premium trial is ending soon!</b>\n\nDon\'t miss out on AI-powered Bitcoin predictions. Tap /premium to keep your access.';
}

return [{ json: { text, userId: $('Build Claude Prompt').first().json.userId } }];

const result = $input.first().json;
const userId = $('Extract Message Text').first().json.userId;
const success = result.ok === true;

console.log(`[Trial Drip] Sent to user ${userId}: ${success ? 'OK' : 'FAILED'}`);

return [{ json: { userId, success, timestamp: new Date().toISOString() } }];
